def run_health_check_server():
    # Back4app uses HTTP, so bind to standard HTTP logic on the requested port
    server_address = ('0.0.0.0', 443)
    httpd = HTTPServer(server_address, SimpleHTTPRequestHandler)
    print("Health check server running on port 443...")
    httpd.serve_forever()

if __name__ == '__main__':
    health_thread = threading.Thread(target=run_health_check_server, daemon=True)
    health_thread.start()
    sleep_time_base = 50
    sleep_time_er = 120
    sleep_time = sleep_time_base
    while True:
        requests.post(
        url=start_mission_url, 
        headers=start_mission_headers, 
        data=start_mission_body,
        timeout=60
        )
        time.sleep(sleep_time)
        response = requests.post(
        url=complete_mission_url, 
        headers=complete_mission_headers, 
        data=complete_mission_body,
        timeout=60
        )
        data = response.json()
        if data.get('error'):
            sleep_time = sleep_time_er
        else:
            sleep_time = sleep_time_base
        time.sleep(0.1)
